_ss = ss_sol(1:nx); u_ss = ss_sol(nx+1); end [du, flag_mpc] = mpc_reg{x_hat, x_ss, u_ss, Tmin_fut, Tmax_fut, Price_fut}; if flag_mpc ~= 0 warning('MPC regulator failed -- applying steady-state input.'); du = 0; else du = full(du); end u = min(max(u_ss + du, u_min), u_max); u_prev = u; end

